import{_ as e,o as i,c as t,a2 as r}from"./chunks/framework.DZrHScmQ.js";const m=JSON.parse('{"title":"Trait-Based Teams","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/principles/trait-based-teams.md","filePath":"ai-native/principles/trait-based-teams.md"}'),l={name:"ai-native/principles/trait-based-teams.md"};function o(s,a,d,h,n,c){return i(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="trait-based-teams" tabindex="-1">Trait-Based Teams <a class="header-anchor" href="#trait-based-teams" aria-label="Permalink to &quot;Trait-Based Teams&quot;">​</a></h1><p><strong>状态：Draft</strong></p><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><p>传统团队主要按 Job Family 划分工作：前端、后端、设计、产品和运营各自拥有固定边界。</p><p>AI 正在降低跨职能产出的门槛。工程师可以生成原型和视觉方案，产品经理可以构建可运行 Demo，设计师可以参与实现和数据分析。岗位仍然存在，但越来越难完整描述一个人在团队中的实际贡献。</p><h2 id="原则" tabindex="-1">原则 <a class="header-anchor" href="#原则" aria-label="Permalink to &quot;原则&quot;">​</a></h2><p>AI Native 小团队应更多按关键 Trait 组队，而不是只按 Job Title 分配责任。</p><p>Trait 描述一个人在不确定环境中的稳定倾向和贡献方式。Job Family 描述专业背景。两者应该结合使用，而不是互相取代。</p><h2 id="五类关键-trait" tabindex="-1">五类关键 Trait <a class="header-anchor" href="#五类关键-trait" aria-label="Permalink to &quot;五类关键 Trait&quot;">​</a></h2><h3 id="builder-pirate" tabindex="-1">Builder / Pirate <a class="header-anchor" href="#builder-pirate" aria-label="Permalink to &quot;Builder / Pirate&quot;">​</a></h3><p>负责把想法变成现实的人，核心能力是执行力和速度。有的公司把这个角色叫 Pirate，意思是想办法尽快达成目的；后续可扩展性和长期债务再交给 Architect 收口。</p><h3 id="architect" tabindex="-1">Architect <a class="header-anchor" href="#architect" aria-label="Permalink to &quot;Architect&quot;">​</a></h3><p>负责让系统可扩展、可维护的人。Builder 做出来的东西可能能跑，Architect 要确保它能持续地跑、大规模地跑。他们关注系统设计、技术选型和长期技术债管理。</p><h3 id="taste-maker" tabindex="-1">Taste Maker <a class="header-anchor" href="#taste-maker" aria-label="Permalink to &quot;Taste Maker&quot;">​</a></h3><p>有审美、有品味的人。在 AI 可以生成大量内容的时代，“什么是好的”变成关键判断。这个人负责把控质量、提升体验，确保产品不只是能用，而是好用、想用。</p><h3 id="signal-reader" tabindex="-1">Signal Reader <a class="header-anchor" href="#signal-reader" aria-label="Permalink to &quot;Signal Reader&quot;">​</a></h3><p>理解用户需求、能从市场中捕捉信号的人。他们持续做用户调研，无论定量还是定性，并不断回答：我们做的东西，是不是市场真正需要的？</p><h3 id="decision-maker" tabindex="-1">Decision Maker <a class="header-anchor" href="#decision-maker" aria-label="Permalink to &quot;Decision Maker&quot;">​</a></h3><p>能在不确定性中做决策、不断产生有效 initiative 的人。小团队没有层层审批来降低决策风险，需要有人能在信息不完整时做判断，并承担后果。</p><h2 id="组队方式" tabindex="-1">组队方式 <a class="header-anchor" href="#组队方式" aria-label="Permalink to &quot;组队方式&quot;">​</a></h2><p>一个小团队通常需要覆盖上述全部 Trait，但不要求每个 Trait 对应一个专职岗位。</p><ul><li>每个人可以拥有多个 Trait。</li><li>每个人应有一到两个主导 Trait，便于建立责任预期。</li><li>Trait 组合随产品阶段变化。</li><li>招聘和组队时检查能力覆盖，不只检查岗位数量。</li><li>专业深度仍然重要，Trait 不能替代必要的工程、设计或领域能力。</li></ul><p>“3-5 人”可以作为早期核心团队的设计假设，不应被写成适用于所有项目的固定规模标准。</p><h2 id="反模式" tabindex="-1">反模式 <a class="header-anchor" href="#反模式" aria-label="Permalink to &quot;反模式&quot;">​</a></h2><ul><li>用 Trait 标签制造新的固定职级</li><li>认为借助 AI 就不再需要专业能力</li><li>Builder / Pirate 只追求速度，把清理工作永久留给 Architect</li><li>Taste Maker 只有个人偏好，没有用户证据</li><li>Signal Reader 只收集反馈，不形成判断</li><li>Decision Maker 拥有权力但不承担结果</li></ul><h2 id="可操作模型" tabindex="-1">可操作模型 <a class="header-anchor" href="#可操作模型" aria-label="Permalink to &quot;可操作模型&quot;">​</a></h2><p>团队如何盘点 Trait、分配主导责任和识别缺口，见 <a href="./../operating-model/trait-based-team.html">Trait-Based Team Model</a>。</p><h2 id="当前验证状态" tabindex="-1">当前验证状态 <a class="header-anchor" href="#当前验证状态" aria-label="Permalink to &quot;当前验证状态&quot;">​</a></h2><p>这是待验证的组队原则。应先在真实项目中记录团队 Trait 覆盖、决策速度、返工和产品结果，再判断是否晋升。</p>',29)])])}const u=e(l,[["render",o]]);export{m as __pageData,u as default};
